/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Cadastro Pessoas"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &filtPesRaz.IsEmpty() print printBlockFilterfiltPesRaz EndIf If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &PesSts.IsEmpty() &FilterPesStsValueDescription = &PesSts.EnumerationDescription()
print printBlockFilterPesSts EndIf If not &PesIsFor.IsEmpty() &FilterPesIsForValueDescription = '' Do Case Case &PesIsFor.ToString().Trim() = !"true" &FilterPesIsForValueDescription = "Somente Fornecedor"
Case &PesIsFor.ToString().Trim() = !"false" &FilterPesIsForValueDescription = "Todas as Pessoas"
EndCase
print printBlockFilterPesIsFor EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESCPF' &PesCpf1.FromString(&GridStateDynamicFilter.Value) If not &PesCpf1.IsEmpty() &PesCpf = &PesCpf1 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector1 = !'PESFAN' &PesFan1.FromString(&GridStateDynamicFilter.Value) If not &PesFan1.IsEmpty() &PesFan = &PesFan1 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector1 = !'RATCOD' &RatCod1.FromString(&GridStateDynamicFilter.Value) If not &RatCod1.IsEmpty() &RatCod = &RatCod1 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDCOD' &PesCidCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod1.IsEmpty() &PesCidCod = &PesCidCod1 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDNOM' &PesCidNom1.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom1.IsEmpty() &PesCidNom = &PesCidNom1 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector1 = !'PESCIDUFECOD' &PesCidUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod1.IsEmpty() &PesCidUfeCod = &PesCidUfeCod1 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector1 = !'PESLOG' &PesLog1.FromString(&GridStateDynamicFilter.Value) If not &PesLog1.IsEmpty() &PesLog = &PesLog1 print printBlockFilterPesLog EndIf Case &DynamicFiltersSelector1 = !'PESBAI' &PesBai1.FromString(&GridStateDynamicFilter.Value) If not &PesBai1.IsEmpty() &PesBai = &PesBai1 print printBlockFilterPesBai EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESCPF' &PesCpf2.FromString(&GridStateDynamicFilter.Value) If not &PesCpf2.IsEmpty() &PesCpf = &PesCpf2 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector2 = !'PESFAN' &PesFan2.FromString(&GridStateDynamicFilter.Value) If not &PesFan2.IsEmpty() &PesFan = &PesFan2 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector2 = !'RATCOD' &RatCod2.FromString(&GridStateDynamicFilter.Value) If not &RatCod2.IsEmpty() &RatCod = &RatCod2 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDCOD' &PesCidCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod2.IsEmpty() &PesCidCod = &PesCidCod2 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDNOM' &PesCidNom2.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom2.IsEmpty() &PesCidNom = &PesCidNom2 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector2 = !'PESCIDUFECOD' &PesCidUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod2.IsEmpty() &PesCidUfeCod = &PesCidUfeCod2 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector2 = !'PESLOG' &PesLog2.FromString(&GridStateDynamicFilter.Value) If not &PesLog2.IsEmpty() &PesLog = &PesLog2 print printBlockFilterPesLog EndIf Case &DynamicFiltersSelector2 = !'PESBAI' &PesBai2.FromString(&GridStateDynamicFilter.Value) If not &PesBai2.IsEmpty() &PesBai = &PesBai2 print printBlockFilterPesBai EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESCPF' &PesCpf3.FromString(&GridStateDynamicFilter.Value) If not &PesCpf3.IsEmpty() &PesCpf = &PesCpf3 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector3 = !'PESFAN' &PesFan3.FromString(&GridStateDynamicFilter.Value) If not &PesFan3.IsEmpty() &PesFan = &PesFan3 print printBlockFilterPesFan EndIf Case &DynamicFiltersSelector3 = !'RATCOD' &RatCod3.FromString(&GridStateDynamicFilter.Value) If not &RatCod3.IsEmpty() &RatCod = &RatCod3 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDCOD' &PesCidCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod3.IsEmpty() &PesCidCod = &PesCidCod3 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDNOM' &PesCidNom3.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom3.IsEmpty() &PesCidNom = &PesCidNom3 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector3 = !'PESCIDUFECOD' &PesCidUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod3.IsEmpty() &PesCidUfeCod = &PesCidUfeCod3 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector3 = !'PESLOG' &PesLog3.FromString(&GridStateDynamicFilter.Value) If not &PesLog3.IsEmpty() &PesLog = &PesLog3 print printBlockFilterPesLog EndIf Case &DynamicFiltersSelector3 = !'PESBAI' &PesBai3.FromString(&GridStateDynamicFilter.Value) If not &PesBai3.IsEmpty() &PesBai = &PesBai3 print printBlockFilterPesBai EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True
using DSWWFornecedores(&filtPesRaz, &PesCod, &PesSts, &PesIsFor, &DynamicFiltersSelector1, &PesCpf1 , &PesFan1, &RatCod1, &PesCidCod1, &PesCidNom1, &PesCidUfeCod1, &PesLog1 , &PesBai1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PesCpf2, &PesFan2, &RatCod2 , &PesCidCod2, &PesCidNom2, &PesCidUfeCod2, &PesLog2, &PesBai2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &PesCpf3, &PesFan3, &RatCod3, &PesCidCod3, &PesCidNom3 , &PesCidUfeCod3, &PesLog3, &PesBai3) &gridPesFan = iif(PesFan.Length() > 30, Substr(PesFan,1, 30) + '...', PesFan) &GridPesTipPessoa = PesIsFor &gridPesCidNom = PesCidUfeCod.Trim() +' / '+ PesCidNom.Trim()
If PesTip = 'J' //JURIDICA &CpfCnpj = PesCnpj Else &CpfCnpj = PesCpf EndIF
&gridPesPrmFon = PesPrmFon
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFornecedoresGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFornecedoresGridState")) Else &GridState.FromXml(&Session.Get(!"WWFornecedoresGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILTPESRAZ" &filtPesRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISFOR" &PesIsFor.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
